import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { getStoredApiBaseUrl, setApiBaseUrl } from '../../../config/apiConfig';

const LoginForm = ({ onSwitchToSignup, embedded = false }) => {
  const [credentials, setCredentials] = useState({
    username: '',
    password: ''
  });
  const [serverUrl, setServerUrl] = useState('');
  const [showServerUrl, setShowServerUrl] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const isLiveSite = typeof window !== 'undefined' && window.location.origin.includes('github.io');

  useEffect(() => {
    if (embedded) return;
    const stored = getStoredApiBaseUrl();
    setServerUrl(stored);
    if (isLiveSite) setShowServerUrl(true);
  }, [isLiveSite, embedded]);

  const { login, error, clearError } = useAuth();

  const handleServerUrlChange = (e) => {
    const value = e.target.value.trim();
    setServerUrl(e.target.value);
    setApiBaseUrl(value || null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    clearError();
    
    const result = await login(credentials);
    
    if (!result.success) {
      setIsLoading(false);
    }
    // If successful, the AuthContext will handle the redirect
  };

  const handleChange = (e) => {
    setCredentials(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };

  const formContent = (
    <form className={embedded ? 'space-y-4' : 'mt-8 space-y-6'} onSubmit={handleSubmit}>
      {!embedded && (
        <div className="text-center">
          <h2 className="text-3xl font-bold text-white">1(800)BIZARRE</h2>
          <p className="mt-2 text-gray-400">Sign in to your account</p>
        </div>
      )}
      {!embedded && isLiveSite && !serverUrl && (
            <div className="bg-amber-900/50 border border-amber-600 text-amber-200 px-4 py-2 rounded text-sm">
              Using the live site — set the Game server URL below (your host’s backend, e.g. <code className="text-amber-100">https://xxx.ngrok-free.app/api</code>). Host runs <code className="text-amber-100">ngrok http 8000</code> and shares that URL.
            </div>
          )}
          {error && (
            <div className="bg-red-900 border border-red-600 text-red-200 px-4 py-3 rounded">
              {error}
              {error.includes('Could not reach game server') && isLiveSite && (
                <p className="mt-2 text-sm text-red-100">
                  Enter the host’s URL above: <strong>https://</strong>their-ngrok-url<strong>/api</strong> (host runs <code>ngrok http 8000</code>).
                </p>
              )}
            </div>
          )}
      {!embedded && (
          <div className="space-y-4">
            <div>
              <button type="button" onClick={() => setShowServerUrl((s) => !s)} className="text-sm text-gray-400 hover:text-gray-300">
                {showServerUrl ? '▼' : '▶'} Game server (optional)
              </button>
              {showServerUrl && (
                <div className="mt-2">
                  <input type="url" value={serverUrl} onChange={handleServerUrlChange} placeholder="https://xxx.ngrok-free.app/api  (host runs: ngrok http 8000)" className="mt-1 block w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-md text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent text-sm" />
                  <p className="mt-1 text-xs text-gray-500">Leave blank for localhost. When playing remotely, the host runs the backend and shares their URL.</p>
                </div>
              )}
            </div>
          </div>
      )}
          <div className="space-y-4">
            <div>
              <label htmlFor="username" className="block text-sm font-medium text-gray-300">
                Username
              </label>
              <input
                id="username"
                name="username"
                type="text"
                required
                value={credentials.username}
                onChange={handleChange}
                className="mt-1 block w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-md text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                placeholder="Enter your username"
              />
            </div>
            
            <div>
              <label htmlFor="password" className="block text-sm font-medium text-gray-300">
                Password
              </label>
              <input
                id="password"
                name="password"
                type="password"
                required
                value={credentials.password}
                onChange={handleChange}
                className="mt-1 block w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-md text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                placeholder="Enter your password"
              />
            </div>
          </div>
          
          <div>
            <button
              type="submit"
              disabled={isLoading}
              className="group relative w-full flex justify-center py-2 px-4 border border-transparent text-sm font-medium rounded-md text-white bg-purple-600 hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isLoading ? 'Signing in...' : 'Sign in'}
            </button>
          </div>
          
          <div className="text-center">
            <button type="button" onClick={onSwitchToSignup} className="text-purple-400 hover:text-purple-300 text-sm">
              Don&apos;t have an account? Sign up
            </button>
          </div>
    </form>
  );

  if (embedded) return formContent;
  return (
    <div className="min-h-screen flex items-center justify-center bg-black">
      <div className="max-w-md w-full space-y-8 p-8">{formContent}</div>
    </div>
  );
};

export default LoginForm; 