import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Menu, X } from 'lucide-react';
import { getStoredApiBaseUrl, setApiBaseUrl } from '../config/apiConfig';
import { LoginForm, SignupForm } from '../features/auth';
import '../styles/LoginFindServer.css';

const SIDENAV_LINK = {
  display: 'block',
  width: '100%',
  padding: '10px 14px',
  textAlign: 'left',
  background: 'transparent',
  border: 'none',
  borderRadius: '6px',
  color: '#e5e7eb',
  fontSize: '14px',
  cursor: 'pointer',
  fontFamily: 'monospace',
};
const LINK_HOVER = { background: '#374151', color: '#fff' };

export default function LoginFindServerPage() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [serverUrl, setServerUrl] = useState('');
  const isLiveSite = typeof window !== 'undefined' && window.location.origin.includes('github.io');

  useEffect(() => {
    setServerUrl(getStoredApiBaseUrl() || '');
    if (isLiveSite) setServerUrl(getStoredApiBaseUrl() || '');
  }, [isLiveSite]);

  const handleServerUrlChange = (e) => {
    const value = e.target.value.trim();
    setServerUrl(e.target.value);
    setApiBaseUrl(value || null);
  };

  const handleMenuAction = (action) => {
    setMenuOpen(false);
    if (action === 'signin') setIsLogin(true);
    if (action === 'play' || action === 'join') {
      document.getElementById('connect')?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const sidebar = (
    <>
      <div
        className="login-page-overlay"
        style={{
          opacity: menuOpen ? 1 : 0,
          pointerEvents: menuOpen ? 'auto' : 'none',
        }}
        onClick={() => setMenuOpen(false)}
        aria-hidden="true"
      />
      <aside
        className="login-page-sidebar"
        style={{
          transform: menuOpen ? 'translateX(0)' : 'translateX(-100%)',
          pointerEvents: menuOpen ? 'auto' : 'none',
        }}
        role="dialog"
        aria-label="Menu"
        aria-hidden={!menuOpen}
      >
        <div className="login-page-sidebar-inner">
          <div className="login-page-menu-header">Menu</div>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('play')}>Play Game</button>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('join')}>Join server</button>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('tools')}>Tools</button>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('characters')}>Characters</button>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('compendium')}>Compendium</button>
          <button type="button" style={SIDENAV_LINK} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, SIDENAV_LINK)} onClick={() => handleMenuAction('community')}>Community</button>
          <button type="button" style={{ ...SIDENAV_LINK, fontWeight: 600 }} onMouseOver={(e) => Object.assign(e.target.style, LINK_HOVER)} onMouseOut={(e) => Object.assign(e.target.style, { ...SIDENAV_LINK, fontWeight: 600 })} onClick={() => handleMenuAction('signin')}>Sign In</button>
        </div>
      </aside>
    </>
  );

  return (
    <div className="login-find-server-page">
      <header className="login-page-header">
        <button
          type="button"
          onClick={() => setMenuOpen(true)}
          aria-label="Open menu"
          className="login-page-hamburger"
        >
          <Menu className="w-6 h-6" />
        </button>
        <h1 className="login-page-title">1(800)BIZARRE</h1>
      </header>

      <main className="login-page-main">
        <section className="login-page-hero">
          <h2 className="login-page-hero-title">1(800) BIZARRE</h2>
          <p className="login-page-hero-sub">TTRPG — connect to a server and sign in.</p>
        </section>

        <section className="login-page-connect" id="connect">
          <div className="login-page-card login-page-connect-card">
            <h3 className="login-page-card-title">Server &amp; account</h3>
            <div className="login-page-server-row">
              <label htmlFor="login-page-server-url" className="login-page-label">Game server URL</label>
              <input
                id="login-page-server-url"
                type="url"
                value={serverUrl}
                onChange={handleServerUrlChange}
                placeholder={isLiveSite ? 'https://xxx.ngrok-free.app/api' : 'http://localhost:8000/api'}
                className="login-page-input"
              />
              <p className="login-page-hint">
                {isLiveSite
                  ? 'Host runs ngrok http 8000 and shares their URL. Leave blank for localhost.'
                  : 'Leave blank for default localhost. For remote play, enter the host’s backend URL.'}
              </p>
            </div>
            <div className="login-page-auth-tabs">
              <button type="button" className={`login-page-tab ${isLogin ? 'active' : ''}`} onClick={() => setIsLogin(true)}>Sign in</button>
              <button type="button" className={`login-page-tab ${!isLogin ? 'active' : ''}`} onClick={() => setIsLogin(false)}>Create account</button>
            </div>
            <div className="login-page-auth-form">
              {isLogin ? (
                <LoginForm embedded onSwitchToSignup={() => setIsLogin(false)} />
              ) : (
                <SignupForm embedded onSwitchToLogin={() => setIsLogin(true)} />
              )}
            </div>
          </div>
        </section>

        <section className="login-page-news">
          <div className="login-page-card login-page-news-card">
            <h3 className="login-page-card-title">Latest news</h3>
            <div className="login-page-news-list">
              <article className="login-page-news-item">
                <time className="login-page-news-date">Feb 2026</time>
                <h4 className="login-page-news-headline">Remote play (ngrok)</h4>
                <p className="login-page-news-body">
                  Host runs backend locally, then <code>ngrok http 8000</code>. Players enter the host’s ngrok URL + <code>/api</code> above.
                </p>
              </article>
              <article className="login-page-news-item">
                <time className="login-page-news-date">Feb 2026</time>
                <h4 className="login-page-news-headline">What’s here</h4>
                <p className="login-page-news-body">
                  Character sheets, server connection, and rules reference. Create an account and point to your game server to start.
                </p>
              </article>
            </div>
          </div>
        </section>
      </main>

      {typeof document !== 'undefined' && createPortal(sidebar, document.body)}
    </div>
  );
}
